import { createContext, useState, useCallback } from 'react'

export const AVATARS = [
  { id: 'av1',  url: 'data:image/png;base64,',   label: 'شاب',          group: 'male' },
  { id: 'av2',  url: 'data:image/png;base64,',   label: 'رجل أعمال',    group: 'male' },
  { id: 'av3',  url: 'data:image/png;base64,',  label: 'شاب برتقالي',  group: 'male' },
  { id: 'av4',  url: 'data:image/png;base64,',  label: 'شاب أزرق',     group: 'male' },
  { id: 'av5',  url: 'data:image/png;base64,',  label: 'ملتحٍ أحمر',   group: 'male' },
  { id: 'av6',  url: 'data:image/png;base64,',  label: 'ملتحٍ أصفر',   group: 'male' },
  { id: 'av7',  url: 'data:image/png;base64,',  label: 'فتاة أصفر',   group: 'female' },
  { id: 'av8',  url: 'data:image/png;base64,', label: 'سيدة برتقالي',group: 'female' },
  { id: 'av9',  url: 'data:image/png;base64,', label: 'سيدة أحمر',   group: 'female' },
  { id: 'av10', url: 'data:image/png;base64,', label: 'امرأة أزرق',  group: 'female' },
  { id: 'av11', url: 'data:image/png;base64,',    label: 'امرأة بنفسجي',group: 'female' },
  { id: 'av12', url: 'data:image/png;base64,',    label: 'امرأة وردي',  group: 'female' }
]

const AuthContext = createContext()

export function AuthProvider({ children }) {
  const [user, setUser] = useState(() => {
    try {
      const saved = localStorage.getItem('n1_user')
      return saved ? JSON.parse(saved) : null
    } catch { return null }
  })

  const login = useCallback((userData) => {
    const u = { ...userData, loggedAt: Date.now() }
    setUser(u)
    localStorage.setItem('n1_user', JSON.stringify(u))
  }, [])

  const logout = useCallback(() => {
    setUser(null)
    localStorage.removeItem('n1_user')
  }, [])

  const updateUser = useCallback((fields) => {
    setUser(prev => {
      const updated = { ...prev, ...fields }
      localStorage.setItem('n1_user', JSON.stringify(updated))
      return updated
    })
  }, [])

  return (
    <AuthContext.Provider value={{ user, login, logout, updateUser, isLoggedIn: !!user }}>
      {children}
    </AuthContext.Provider>
  )
}

export { AuthContext }
